/**
 * Awesome Free GenAI — Frontend Application
 *
 * Loads data.json (generated by the build script) and renders an interactive,
 * searchable, filterable card grid.
 */

(function () {
  "use strict";

  let allCategories = [];

  // ── DOM refs ──────────────────────────────────────────────
  const searchInput = document.getElementById("search-input");
  const categoryFilter = document.getElementById("category-filter");
  const resultsCount = document.getElementById("results-count");
  const container = document.getElementById("categories-container");
  const themeToggle = document.getElementById("theme-toggle");
  const themeIcon = themeToggle.querySelector(".theme-icon");

  // ── Theme ─────────────────────────────────────────────────
  function initTheme() {
    const saved = localStorage.getItem("theme");
    const prefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
    const theme = saved || (prefersDark ? "dark" : "light");
    applyTheme(theme);
  }

  function applyTheme(theme) {
    document.documentElement.setAttribute("data-theme", theme);
    localStorage.setItem("theme", theme);
    themeIcon.textContent = theme === "dark" ? "☀️" : "🌙";
  }

  themeToggle.addEventListener("click", () => {
    const current = document.documentElement.getAttribute("data-theme");
    applyTheme(current === "dark" ? "light" : "dark");
  });

  // ── Data loading ──────────────────────────────────────────
  async function loadData() {
    try {
      const resp = await fetch("data.json");
      if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
      allCategories = await resp.json();
      populateCategoryFilter();
      render();
    } catch (err) {
      container.innerHTML =
        '<div class="empty-state"><p>Failed to load data. Please try again later.</p></div>';
      console.error("Failed to load data.json:", err);
    }
  }

  function populateCategoryFilter() {
    for (const cat of allCategories) {
      const opt = document.createElement("option");
      opt.value = cat.category;
      opt.textContent = `${cat.icon || ""} ${cat.category}`;
      categoryFilter.appendChild(opt);
    }
  }

  // ── Rendering ─────────────────────────────────────────────
  function render() {
    const query = searchInput.value.toLowerCase().trim();
    const selectedCategory = categoryFilter.value;

    let totalVisible = 0;
    let html = "";

    for (const cat of allCategories) {
      if (selectedCategory !== "all" && cat.category !== selectedCategory) continue;

      const filteredTools = (cat.agents || []).filter((tool) => {
        if (query) {
          const haystack = [tool.name, tool.description, tool.location || "", tool.free_tier || ""].join(" ").toLowerCase();
          if (!haystack.includes(query)) return false;
        }
        return true;
      });

      if (filteredTools.length === 0) continue;

      totalVisible += filteredTools.length;

      html += `
        <section class="category-section">
          <div class="category-header">
            <h2>${cat.icon || ""} ${cat.category}</h2>
          </div>
          <p class="category-description">${cat.description || ""}</p>
          <div class="tools-grid">
            ${filteredTools.map(renderCard).join("")}
          </div>
        </section>
      `;
    }

    if (totalVisible === 0) {
      html = '<div class="empty-state"><p>No tools match your filters. Try adjusting your search.</p></div>';
    }

    container.innerHTML = html;
    resultsCount.textContent = `Showing ${totalVisible} tool${totalVisible !== 1 ? "s" : ""}`;
  }

  const FLAG_MAP = {
    'USA': '🇺🇸',
    'France': '🇫🇷',
    'China': '🇨🇳',
    'Australia': '🇦🇺',
    'Singapore': '🇸🇬',
    'Sweden': '🇸🇪',
    'Hong Kong': '🇭🇰',
    'India': '🇮🇳',
    'Israel': '🇮🇱',
    'Prague': '🇨🇿',
    'Open Source': '🌐',
  };

  function locationFlag(location) {
    return FLAG_MAP[location] || '🌐';
  }

  function renderCard(tool) {
    return `
      <article class="tool-card">
        <div class="tool-card-header">
          <div class="tool-name"><a href="${tool.url}" target="_blank" rel="noopener">${tool.name}</a> ${locationFlag(tool.location)}</div>
        </div>
        <ul class="tool-details">
          <li>📝 ${tool.description}</li>
          ${tool.free_tier ? `<li>🆓 ${tool.free_tier}</li>` : ""}
        </ul>
      </article>
    `;
  }

  // ── Event listeners ───────────────────────────────────────
  searchInput.addEventListener("input", render);
  categoryFilter.addEventListener("change", render);

  // ── Init ──────────────────────────────────────────────────
  initTheme();
  loadData();
})();
